queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?channel_value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:channel_id ?cg . ?child a :Channels ; p:channel_id ?cg . ?l p:representative_id ?pg . ?parent a :Customer_Service_Representatives ; p:id ?pg . } GROUP BY ?child }
  ?child p:channel_value ?channel_value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Customer_Service_Representatives } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?channel_value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:channel_id ?cg . ?child a :Channels ; p:channel_id ?cg . ?l p:representative_id ?pg . ?parent a :Customer_Service_Representatives ; p:id ?pg . } GROUP BY ?child }
  ?child p:channel_value ?channel_value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Customer_Service_Representatives } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?email ?channel_value WHERE {
  ?customer_service_representatives_channels a :Customer_Service_Representatives_Channels .
  ?channels a :Channels .
  ?customer_service_representatives_channels p:hasChannels ?channels .
  ?customer_service_representatives a :Customer_Service_Representatives .
  ?customer_service_representatives_channels p:hasCustomer_Service_Representatives ?customer_service_representatives .
  ?customer_service_representatives p:email ?email .
  ?channels p:channel_value ?channel_value .
} }
}
